367:     private void rewriteRepartitionNodes() {
368:         final Set<BaseRepartitionNode<?, ?>> nodes = new NodesWithRelaxedNullKeyJoinDownstream(root).find();
369:         for (final BaseRepartitionNode<?, ?> partitionNode : nodes) {
