1013:         Objects.requireNonNull(applicationId, "topology has not completed optimization");
1014: 
1015:         final Map<String, ProcessorNode<?, ?, ?, ?>> processorMap = new LinkedHashMap<>();
1016:         final Map<String, SourceNode<?, ?>> topicSourceMap = new HashMap<>();
1017:         final Map<String, SinkNode<?, ?>> topicSinkMap = new HashMap<>();
1018:         final Map<String, StateStore> stateStoreMap = new LinkedHashMap<>();
1019:         final Set<String> repartitionTopics = new HashSet<>();
1020: 
1021:         // create processor nodes in a topological order ("nodeFactories" is already topologically sorted)
